  name: string;
  payload: any;
  expectedStatus: "VALID" | "INVALID";
}

const testCases: TestCase[] = [
  {
    name: "1. Valid Payload",
    payload: { percent: 25, amount: 99.99, validityDays: 30, appliesTo: "cart" },
